from collections.abc import Callable, Iterable
from dataclasses import dataclass

from harness.context import CaseContext


Check = Callable[[CaseContext], bool]


@dataclass(frozen=True)
class CheckResult:
    case_id: str
    check_name: str
    passed: bool
    detail: str


def run_matrix(
    case_ids: Iterable[str], checks: Iterable[tuple[str, Check]]
) -> list[CheckResult]:
    root = CaseContext()
    scheduled: list[tuple[CaseContext, str, Check]] = []
    check_list = list(checks)

    for case_id in case_ids:
        context = root.bind(case_id)
        for check_name, check in check_list:
            scheduled.append((context, check_name, check))

    results: dict[str, CheckResult] = {}
    for context, check_name, check in scheduled:
        try:
            passed = bool(check(context))
            detail = "" if passed else "returned false"
        except Exception as exc:
            passed = False
            detail = f"{type(exc).__name__}: {exc}"

        results[check_name] = CheckResult(
            case_id=context.case_id,
            check_name=check_name,
            passed=passed,
            detail=detail,
        )

    return list(results.values())

