from harness.runner import run_matrix


def test_single_target_keeps_each_distinct_probe():
    results = run_matrix(
        ["staging"],
        [
            ("health", lambda context: True),
            ("identity", lambda context: context.case_id == "staging"),
        ],
    )

    assert [(item.case_id, item.check_name, item.passed) for item in results] == [
        ("staging", "health", True),
        ("staging", "identity", True),
    ]
